var import_obsidian16 = require("obsidian");
init_helpers();
var PriorityInputModal = class extends import_obsidian16.Modal {
  constructor(app, currentPriority, onSubmit) {
    super(app);
    this.priority = currentPriority;
    this.onSubmit = onSubmit;
  }
  onOpen() {
    const { contentEl } = this;
    contentEl.empty();
    contentEl.createEl("h2", { text: t("SET_PRIORITY") });
    contentEl.createEl("p", {
      text: t("PRIORITY_DESC"),
      cls: "priority-modal-desc"
    });
    new import_obsidian16.Setting(contentEl).setName(t("PRIORITY_LABEL")).setDesc(`${t("PRIORITY_DESC")}`).addSlider(
      (slider2) => slider2.setLimits(1, 10, 1).setValue(this.priority).setDynamicTooltip().onChange((value) => {
        this.priority = value;
      })
    );
    const valueDisplay = contentEl.createDiv({
      text: `${t("PRIORITY")}: ${this.priority}`,
      cls: "priority-value-display"
    });
    valueDisplay.addClass("syro-priority-value-display");
    const updateDisplay = () => {
      valueDisplay.setText(`${t("PRIORITY")}: ${this.priority}`);
    };
    const slider = contentEl.querySelector('input[type="range"]');
    if (slider) {
      slider.addEventListener("input", () => {
        this.priority = parseInt(slider.value);
        updateDisplay();
      });
    }
    const buttonContainer = contentEl.createDiv({ cls: "modal-button-container" });
    buttonContainer.addClass("syro-priority-modal-actions");
    const cancelButton = buttonContainer.createEl("button", { text: t("CANCEL") });
    cancelButton.addEventListener("click", () => {
      this.close();
    });
    const submitButton = buttonContainer.createEl("button", {
      text: t("SAVE"),
      cls: "mod-cta"
    });
    submitButton.addEventListener("click", () => {
      if (this.priority < 1 || this.priority > 10) {
        new import_obsidian16.Notice(t("PRIORITY_RANGE_ERROR"));
        return;
      }
      this.onSubmit(this.priority);
      this.close();
    });
  }
  onClose() {
    const { contentEl } = this;
    contentEl.empty();
  }
};

